  3→// ── Vote toggle ──
  4→export const toggleVoteService = async (storyId, userId) => {
  5→    if (!storyId || !userId) {
  6→        throw { status: 400, error: 'storyId and userId are required' };
  7→    }
  8→
  9→    const { data: existing } = await supabase
 10→        .from('story_votes')
 11→        .select('id')
 12→        .eq('story_id', storyId)
 13→        .eq('user_id', userId)
 14→        .maybeSingle();
 15→
 16→    if (!existing) {
 17→        const { error } = await supabase
 18→            .from('story_votes')
 19→            .insert({ story_id: storyId, user_id: userId });
 20→
 21→        if (error) {
 22→            console.error('supabase error inserting vote:', error.message);
 23→            throw { status: 500, error: 'failed to vote' };
 24→        }
 25→
 26→        // Increment vote_count
 27→        const { data: story } = await supabase
 28→            .from('stories')
 29→            .select('vote_count')
 30→            .eq('id', storyId)
 31→            .single();
 32→        if (story) {
 33→            await supabase
 34→                .from('stories')
 35→                .update({ vote_count: (story.vote_count || 0) + 1 })
 36→                .eq('id', storyId);
 37→        }
 38→
 39→        return { message: 'voted' };
 40→    } else {
 41→        const { error } = await supabase
 42→            .from('story_votes')
 43→            .delete()
 44→            .eq('story_id', storyId)
 45→            .eq('user_id', userId);
 46→
 47→        if (error) {
 48→            console.error('supabase error deleting vote:', error.message);
 49→            throw { status: 500, error: 'failed to unvote' };
 50→        }
 51→
 52→        // Decrement vote_count
 53→        const { data: story } = await supabase
 54→            .from('stories')
 55→            .select('vote_count')
 56→            .eq('id', storyId)
 57→            .single();
 58→        if (story) {
 59→            await supabase
 60→                .from('stories')
 61→                .update({ vote_count: Math.max(0, (story.vote_count || 0) - 1) })
 62→                .eq('id', storyId);
 63→        }
 64→
 65→        return { message: 'unvoted' };
 66→    }
 67→};
