168→        throw { status: 500, error: 'failed to fetch comment counts' };
169→    }
170→
171→    // Aggregate counts per paragraph_index
172→    const counts = {};
173→    (data || []).forEach(row => {
174→        const idx = row.paragraph_index;
175→        counts[idx] = (counts[idx] || 0) + 1;
176→    });
177→
178→    return counts;
