 99→storyRouter.get('/chapters/:chapterId/comments', optionalAuth, getCommentsController);
100→storyRouter.get('/chapters/:chapterId/comment-counts', optionalAuth, getCommentCountsController);
101→storyRouter.post('/chapters/:chapterId/comments', requireAuth, addCommentController);
102→storyRouter.post('/stories/:storyId/progress', requireAuth, saveProgressController);
103→storyRouter.get('/stories/:storyId/progress', requireAuth, getProgressController);
104→
105→export default storyRouter;
